INSERT INTO `cartas` VALUES (1,'a9d68cf5-3055-4ec9-9893-244bfd7046be','Action News Crew','Reporteros del telenoticias','Creature — Human Citizen','Vigilance\nChannel — {6}, Discard this card: Put a +1/+1 counter on each creature you control. Draw a card.','{1}{W}',2,'2','2',NULL),(2,'f33217cc-175f-45e8-bc69-801f41cb4495','Agent Bishop, Man in Black','Agente Alfil, hombre de negro','Legendary Creature — Human Soldier','At the beginning of combat on your turn, put a +1/+1 counter on each of up to two target creatures.','{2}{W}',3,'1','2',NULL),(3,'3f166376-2739-411c-8f42-96f2ef28ef86','April O\'Neil, Kunoichi Trainee','April O\'Neil, kunoichi aprendiz','Legendary Creature — Human Ninja','When April O\'Neil enters, scry 2. (Look at the top two cards of your library, then put any number of them on the bottom and the rest on top in any order.)\nApril O\'Neil can\'t be blocked by creatures with power 3 or greater.','{1}{W}',2,'2','2',NULL),(4,'8f0777bc-4fca-4601-beed-1fd060f28075','Dimensional Exile','Exilio dimensional','Enchantment — Aura','Enchant basic land you control\nWhen this Aura enters, exile target creature an opponent controls until this Aura leaves the battlefield.','{1}{W}',2,NULL,NULL,NULL),(5,'e2ef355a-2472-47e0-9b2e-987994291921','East Wind Avatar','Avatar del viento del este','Creature — Bird Spirit Avatar','Flying, vigilance\nAlliance — Whenever another creature you control enters, this creature gets +1/+0 until end of turn.','{3}{W}',4,'2','4',NULL),(6,'79a9fc1c-a6a9-483a-9ba7-d09fe41760c3','Featherbrained Filcher','Caco cabeza de chorlito','Creature — Bird Mutant','Flying\nWhen this creature leaves the battlefield, create a Food token. (It\'s an artifact with \"{2}, {T}, Sacrifice this token: You gain 3 life.\")','{W}',1,'0','2',NULL),(7,'9a334434-072a-4486-810a-63efb29dea6d','Grounded for Life','Castigado de por vida','Instant','This spell costs {3} less to cast if it targets a tapped creature.\nDestroy target creature.','{4}{W}',5,NULL,NULL,NULL),(8,'e08b19ca-f9d7-4c33-b37a-a77b37aabf1b','Hamato Guardian Stance','Postura de guardián de Hamato','Instant','Target creature gets +1/+3 and gains flying until end of turn. Scry 1. (Look at the top card of your library. You may put that card on the bottom.)','{W}',1,NULL,NULL,NULL),(9,'84a56740-8563-4ce5-8560-d44998d7f80d','High-Flying Ace','As volador','Creature — Bird Mutant','Flying\n{3}{W}: Target creature without flying gains flying until end of turn. Activate only as a sorcery.','{2}{W}',3,'2','3',NULL),(10,'b55da4d3-2cad-4c89-ad3f-7d8397b64d52','Jennika, Bad Apple Big Sister','Jennika, hermana mayor corrupta','Legendary Creature — Mutant Ninja Turtle','When Jennika enters, create a 2/2 red Mutant creature token.\nPlainscycling {2} ({2}, Discard this card: Search your library for a Plains card, reveal it, put it into your hand, then shuffle.)','{4}{W}',5,'3','3',NULL),(11,'e7cd87d4-028c-49d9-9416-69f57e7dfec5','Koya, Death from Above','Koya, muerte alada','Legendary Creature — Mutant Ninja Bird','Flying\nWhen Koya enters, exile up to one other target creature. At the beginning of the next end step, you may pay {3}{B}. If you don\'t, return that card to the battlefield under its owner\'s control.','{2}{W}',3,'2','1',NULL),(12,'6a51bb21-0c01-4ad8-99d7-17685db90b69','The Last Ronin\'s Technique','Técnica del último ronin','Instant','Sneak {1}{W} (You may cast this spell for {1}{W} if you also return an unblocked attacker you control to hand during the declare blockers step.)\nCreate three 1/1 white Ninja Turtle Spirit creature tokens. If this spell\'s sneak cost was paid, they enter tapped and attacking.','{3}{W}',4,NULL,NULL,NULL),(13,'134430b7-d566-485a-bd5c-7db8a285f4ca','Leader\'s Talent','Talento: liderazgo','Enchantment — Class','(Gain the next level as a sorcery to add its ability.)\nWhenever you attack, put a +1/+1 counter on target attacking creature.\n{2}{W}: Level 2\nWhenever a creature you control leaves the battlefield, if it had a counter on it, you gain 2 life.\n{3}{W}: Level 3\nWhenever you cast a spell, put a +1/+1 counter on each creature you control.','{1}{W}',2,NULL,NULL,NULL),(14,'6496eea7-38f5-4428-a379-b08b0eeb5239','Leonardo, Big Brother','Leonardo, hermano mayor','Legendary Creature — Mutant Ninja Turtle','Sneak {W} (You may cast this spell for {W} if you also return an unblocked attacker you control to hand during the declare blockers step. He enters tapped and attacking.)\nLeonardo gets +1/+0 for each other creature you control.','{2}{W}',3,'1','3',NULL),(15,'933fe6e5-8d00-4411-aa54-7780382c1ea6','Leonardo, Cutting Edge','Leonardo, vanguardia afilada','Legendary Creature — Mutant Ninja Turtle','Sneak {W} (You may cast this spell for {W} if you also return an unblocked attacker you control to hand during the declare blockers step. He enters tapped and attacking.)\nLifelink\nWhenever you gain life, put a +1/+1 counter on Leonardo.','{1}{W}',2,'1','1',NULL),(16,'348c7e22-2179-41b8-a5d2-8dd488e7e66d','Leonardo, Leader in Blue','Leonardo, líder de azul','Legendary Creature — Mutant Ninja Turtle','Sneak {3}{W}{W} (You may cast this spell for {3}{W}{W} if you also return an unblocked attacker you control to hand during the declare blockers step. He enters tapped and attacking.)\nWhen Leonardo enters, if his sneak cost was paid, creatures you control get +2/+0 until end of turn.\n{1}{W}: Leonardo gains first strike until end of turn.','{W}',1,'2','1',NULL),(17,'74e3243b-6707-4769-8767-7cf2ef71009a','Leonardo, Sewer Samurai','Leonardo, samurái del sumidero','Legendary Creature — Mutant Ninja Turtle Samurai','Sneak {2}{W}{W}\nDouble strike\nDuring your turn, you may cast creature spells with power or toughness 1 or less from your graveyard. If you cast a spell this way, that creature enters with a finality counter on it. (If a creature with a finality counter on it would die, exile it instead.)','{3}{W}',4,'3','3',NULL),(18,'e98c2af9-1393-487d-b8e9-f49a67bb7296','Leonardo\'s Technique','Técnica de Leonardo','Sorcery','Sneak {1}{W} (You may cast this spell for {1}{W} if you also return an unblocked attacker you control to hand during the declare blockers step.)\nReturn one or two target creature cards each with mana value 3 or less from your graveyard to the battlefield.','{3}{W}',4,NULL,NULL,NULL),(19,'212fdb7c-1c7e-4eed-b1ed-bcc14a425da8','Lita, Little Orphan Amphibian','Lita, huerfanita anfibia','Legendary Creature — Mutant Ninja Turtle','Alliance — Whenever another creature you control enters, choose one that hasn\'t been chosen this turn.\n• Put a +1/+1 counter on Lita.\n• Create a Food token. (It\'s an artifact with \"{2}, {T}, Sacrifice this token: You gain 3 life.\")\n• Scry 1.','{1}{W}',2,'2','1',NULL),(20,'8226f31d-6f51-49c3-87f7-0c68f7f4f9ce','Make Your Move','Poner en jaque','Instant','Destroy target artifact, enchantment, or creature with power 4 or greater.','{2}{W}',3,NULL,NULL,NULL),(21,'fcdc7dfc-04b5-411a-ab49-282b9c2608e2','Mighty Mutanimals','Poderosos mutanimales','Creature — Mutant Rebel','When this creature enters, create a 2/2 red Mutant creature token.\nAlliance — Whenever another creature you control enters, put a +1/+1 counter on target creature you control.','{2}{W}{W}',4,'2','1',NULL),(22,'2519ccc0-c206-41fb-aa15-2ef88025ff96','Prehistoric Pet','Mascota prehistórica','Creature — Dinosaur Ninja','This creature can\'t be blocked by creatures with greater power.\n{1}{W}, {T}: Return another target creature you control to its owner\'s hand. Activate only during your turn.','{W}',1,'1','2',NULL),(23,'e9685c61-e33d-4ae0-9dd3-7fd0df5eb46f','Quintessential Katana','Katanas características','Artifact — Equipment','Equipped creature gets +1/+1 and has \"Whenever this creature deals combat damage, untap it and you gain 2 life.\"\nWhenever a Ninja you control enters, you may attach this Equipment to it.\nEquip {2} ({2}: Attach to target creature you control. Equip only as a sorcery.)','{W}',1,NULL,NULL,NULL),(24,'b529f6b0-c6b2-4eb3-bb48-178e1eda75f3','Sally Pride, Lioness Leader','Sally Pride, leona líder','Legendary Creature — Cat Mutant Rebel','When Sally Pride enters, create X 2/2 red Mutant creature tokens, where X is the number of nontoken creatures you control.\nWhenever Sally Pride attacks, put a +1/+1 counter on each creature you control.','{3}{W}{W}',5,'2','4',NULL),(25,'45d40cdb-21cc-4569-a894-83dd3026c947','Triceraton Commander','Comandante triceratón','Creature — Dinosaur Soldier','Flying\nWhenever this creature attacks, Dinosaurs you control other than this creature get +1/+1 and gain flying until end of turn.\nWhen this creature enters, create X 2/2 white Dinosaur Soldier creature tokens.','{X}{X}{W}{W}',2,'2','2',NULL),(26,'0f35cf85-6783-4d69-b5e6-a81f7c1f21e7','Turncoat Kunoichi','Kunoichi desleal','Creature — Mutant Ninja Fox','Sneak {2}{W}{B} (You may cast this spell for {2}{W}{B} if you also return an unblocked attacker you control to hand during the declare blockers step. It enters tapped and attacking.)\nWhen this creature enters, choose target creature an opponent controls. Exile that creature until this creature leaves the battlefield. If this creature\'s sneak cost was paid, instead exile the chosen creature.','{2}{W}',3,'3','2',NULL),(27,'cff5aca2-72c5-4053-a32c-c0bd3174c52d','Turtles Forever','Tortugas para siempre','Instant','Search your library and/or outside the game for exactly four legendary creature cards you own with different names, then reveal those cards. An opponent chooses two of them. Put the chosen cards into your hand and shuffle the rest into your library.','{3}{W}',4,NULL,NULL,NULL),(28,'989b93fe-cad0-4890-a228-8a20ca666f10','Uneasy Alliance','Alianza incómoda','Enchantment — Aura','Enchant creature\nEnchanted creature can\'t attack or block.\n{5}, Sacrifice this Aura: Exile enchanted creature. You create a 1/1 black Ninja creature token. Activate only as a sorcery.','{1}{W}',2,NULL,NULL,NULL),(29,'d379a919-02cd-46fd-a6ce-b66a77745ae7','April O\'Neil, Hacktivist','April O\'Neil, hacktivista','Legendary Creature — Human Scientist','At the beginning of your end step, draw a card for each card type among spells you\'ve cast this turn.','{3}{U}',4,'1','5',NULL),(30,'1c371003-e4f0-4d7c-b021-273176772f97','April, Reporter of the Weird','April, reportera de lo extraño','Legendary Creature — Human Detective','Whenever April deals combat damage to a player, draw that many cards, then discard a card.','{2}{U}',3,'2','2',NULL),(31,'679480aa-f9ad-4a6c-bd79-db9f9f75433d','Bespoke Bō','Bō bárbaro','Artifact — Equipment','When this Equipment enters, return up to one other target nonland permanent to its owner\'s hand.\nEquipped creature gets +2/+1 and has vigilance.\nEquip {3} ({3}: Attach to target creature you control. Equip only as a sorcery.)','{2}{U}',3,NULL,NULL,NULL),(32,'434e720f-2bfa-49b6-a5ac-fe0c0b24764d','Buzz Bots','Moscadrones','Artifact Creature — Robot Insect','Flying, vigilance\nWhen this creature dies, draw a card.','{1}{U}',2,'1','1',NULL),(33,'b24a87af-407f-4c58-80b4-caab9c65a233','Crustacean Commando','Comando crustáceo','Creature — Crab Mutant Soldier','When this creature enters, create a Mutagen token. (It\'s an artifact with \"{1}, {T}, Sacrifice this token: Put a +1/+1 counter on target creature. Activate only as a sorcery.\")','{1}{U}',2,'0','3',NULL),(34,'df54b79d-f31d-4582-86c0-1d34ec77be0f','Does Machines','Es inventor','Enchantment — Class','(Gain the next level as a sorcery to add its ability.)\nWhen this Class enters, mill two cards, draw two cards, then discard two cards.\n{1}{U}: Level 2\nWhen this Class becomes level 2, return up to two target artifact cards from your graveyard to your hand.\n{4}{U}: Level 3\nAt the beginning of combat on your turn, put three +1/+1 counters on target artifact you control. If it isn\'t a creature, it becomes a 0/0 Robot creature in addition to its other types.','{1}{U}',2,NULL,NULL,NULL),(35,'bb6aef0d-052b-44e6-b4cd-2d2eafd84969','Donatello, Gadget Master','Donatello, maestro de dispositivos','Legendary Creature — Mutant Ninja Turtle','Sneak {1}{U} (You may cast this spell for {1}{U} if you also return an unblocked attacker you control to hand during the declare blockers step. He enters tapped and attacking.)\nWhenever Donatello deals combat damage to a player, create a token that\'s a copy of target artifact you control.','{2}{U}',3,'3','2',NULL),(36,'f6a7838d-380f-4752-a647-c55c2a0eb6e2','Donatello, Mutant Mechanic','Donatello, mecánico mutante','Legendary Creature — Mutant Ninja Turtle','{T}: Put three +1/+1 counters on target artifact you control. If it isn\'t a creature, it becomes a 0/0 Robot creature in addition to its other types. Activate only as a sorcery.\nWhenever an artifact you control is put into a graveyard from the battlefield, if it had counters on it, put those counters on up to one target artifact or creature you control.','{3}{U}',4,'3','5',NULL),(37,'f84850bc-6348-449e-bd82-bb39e2119bec','Donatello, Turtle Techie','Donatello, tortuga tecnómana','Legendary Creature — Mutant Ninja Turtle','When Donatello enters, if you control an artifact, draw a card.','{3}{U}',4,'3','4',NULL),(38,'194af2be-50c7-484b-bdd3-402bad70335b','Donatello, Way with Machines','Donatello, mañoso con las máquinas','Legendary Creature — Mutant Ninja Turtle','Flying\nWhenever an artifact you control enters, put a +1/+1 counter on Donatello.','{2}{U}',3,'1','2',NULL),(39,'194284f7-cf92-4d9f-a8ce-e4dc3505ab7a','Donatello\'s Technique','Técnica de Donatello','Sorcery','Sneak {U} (You may cast this spell for {U} if you also return an unblocked attacker you control to hand during the declare blockers step.)\nDraw two cards.','{2}{U}',3,NULL,NULL,NULL),(40,'c04d4fd4-e5aa-431d-824b-8bc94245f103','Fugitive Droid','Androide fugitivo','Artifact Creature — Robot Scientist','This creature can\'t be blocked if an artifact entered the battlefield under your control this turn.\n{U}, Sacrifice this creature: Counter target spell that targets an artifact or creature you control.','{U}',1,'1','1',NULL),(41,'9be19bdf-db1e-433e-8be4-8b985a568211','Kitsune, Dragon\'s Daughter','Kitsune, hija del dragón','Legendary Creature — Fox Warlock Avatar','Vigilance\nWhenever Kitsune enters or deals combat damage to a player, you may exchange control of two other target creatures controlled by different players.','{4}{U}{U}',6,'6','6',NULL),(42,'3e0f8ab3-75a6-49a2-a228-fa720cbde3d8','Kitsune\'s Technique','Técnica de Kitsune','Instant','Sneak {1}{U} (You may cast this spell for {1}{U} if you also return an unblocked attacker you control to hand during the declare blockers step.)\nTarget opponent mills half their library, rounded up.','{4}{U}{U}',6,NULL,NULL,NULL),(43,'52562194-4a97-40d2-aa73-7827f7834f2f','Krang, Master Mind','Krang, mente maestra','Legendary Artifact Creature — Utrom Warrior','Affinity for artifacts (This spell costs {1} less to cast for each artifact you control.)\nWhen Krang enters, if you have fewer than four cards in hand, draw cards equal to the difference.\nKrang gets +1/+0 for each other artifact you control.','{6}{U}{U}',8,'1','4',NULL),(44,'7df45a2a-75bc-4343-8dad-3a642efd13ee','Metalhead','Cabeza de Metal','Legendary Artifact Creature — Robot Turtle','When Metalhead enters, return up to one other target artifact or creature to its owner\'s hand.\n{R}, Sacrifice another artifact: Put a +1/+1 counter on Metalhead. He gains menace and haste until end of turn.','{4}{U}',5,'4','4',NULL),(45,'0d80d0f7-a436-431c-a54e-e7dd7dbba8de','Mind Transfer Protocol','Protocolo de transferencia mental','Instant','Until end of turn, target artifact or creature becomes an artifact creature with base power and toughness 4/5.\nDraw a card.','{2}{U}',3,NULL,NULL,NULL),(46,'fa3ae120-756d-4c52-91f9-235767539d67','Mondo Gecko','Mondo Gecko','Legendary Creature — Lizard Mutant','{1}, Discard a card: Until end of turn, Mondo Gecko becomes the color of your choice and gains hexproof from that color.\nWhenever Mondo Gecko deals combat damage to a player, draw a card for each color among permanents you control.','{1}{U}{U}',3,'2','3',NULL),(47,'3407fe41-fdd3-4119-8f70-4bc4590a379f','Negate','Negar','Instant','Counter target noncreature spell.','{1}{U}',2,NULL,NULL,NULL),(48,'c1c5f9da-1396-4406-b803-b64f66b8e49d','Ooze Spill','Derrame de ooze','Instant','Counter target spell. Create a Mutagen token. (It\'s an artifact with \"{1}, {T}, Sacrifice this token: Put a +1/+1 counter on target creature. Activate only as a sorcery.\")','{1}{U}{U}',3,NULL,NULL,NULL),(49,'698098b8-b8e4-4e88-b13a-6b039579d192','Ray Fillet, Man Ray','Ray Fillet, hombre raya','Legendary Creature — Fish Mutant','Flying\nWhen Ray Fillet enters, create a Mutagen token. (It\'s an artifact with \"{1}, {T}, Sacrifice this token: Put a +1/+1 counter on target creature. Activate only as a sorcery.\")\n{2}, Remove a +1/+1 counter from a creature you control: Draw a card.','{3}{U}',4,'3','3',NULL),(50,'6c754808-86a6-43d3-8aeb-96ec19f7396c','Renet, Temporal Apprentice','Renet, aprendiz temporal','Legendary Creature — Human Wizard','Flash\nWhen Renet enters, return each other nonland permanent that entered this turn to its owner\'s hand.','{3}{U}{U}',5,'4','3',NULL),(51,'d8b5de6d-8654-4550-bccb-79de6cbef4d5','Retro-Mutation','Retromutación','Enchantment — Aura','Flash\nEnchant creature\nEnchanted creature is a Turtle with base power and toughness 0/1. It can\'t attack and loses all abilities. (It also loses all other creature types.)','{2}{U}',3,NULL,NULL,NULL),(52,'a3ee8565-f34c-4073-bc94-3fe9ec6bbe8a','Return to the Sewers','Regresar a las alcantarillas','Instant','Target creature\'s owner puts it on their choice of the top or bottom of their library. You create a Mutagen token. (It\'s an artifact with \"{1}, {T}, Sacrifice this token: Put a +1/+1 counter on target creature. Activate only as a sorcery.\")','{3}{U}',4,NULL,NULL,NULL),(53,'25c83d45-581f-48ba-b6bb-feb66e8a65c7','Sewer-veillance Cam','Cámara de bichilancia','Artifact','Flash\nWhen this ar